    ds_tariff.setCellData(row, "ctrtNo", ds_ctrtBase.getCellData(baseRow, "ctrtNo"));
    ds_tariff.setCellData(row, "transMdCtrtTrfSeq", "1");
    ds_tariff.setCellData(row, "selpchItemCd", acb_selpchItemCd.getValue());
